// Battery Export Strategy Calculator
// Calculates optimal discharge strategy for the evening peak feed-in period
// Outputs to HA helper entities consumed by the Peak Export Control automation
//
// ── CONFIGURATION ────────────────────────────────────────────────────────────
// Edit these constants to match your system:

const EXPORT_PERIOD_START_HOUR = 18;           // ← REPLACE: peak export start (24h)
const EXPORT_PERIOD_END_HOUR = 20;             // ← REPLACE: peak export end (24h)
const EXPORT_PERIOD_DURATION = 2;              // ← REPLACE: duration in hours
const MAX_EXPORT_CAP_KWH = 10;                 // ← REPLACE: your retailer's export cap kWh (if any)
const BASE_OVERNIGHT_RESERVE_KWH = 8;          // ← REPLACE: base overnight battery reserve kWh
const AIRCON_ADDITIONAL_RESERVE_KWH = 8;       // ← REPLACE: additional reserve if aircon expected kWh
const SAFETY_BUFFER_KWH = 1;                   // Safety buffer added to reserve
const MIN_SOC_PERCENT = 20;                    // ← REPLACE: absolute minimum SOC %
const ZERO_HERO_MIN_BATTERY_SOC = 25;          // ← REPLACE: minimum SOC to maintain for Zero Hero / feed-in bonus %

// ── SENSOR PARSING ───────────────────────────────────────────────────────────
let batterySOC = parseFloat(msg.payload.battery_soc) || 0;
let batteryCapacity = parseFloat(msg.payload.battery_capacity) || 0;
let solarRemaining = (parseFloat(msg.payload.solar_remaining) || 0) / 1000;
let currentHouseholdPower = (parseFloat(msg.payload.household_power) || 0) / 1000;
let airconOvernightExpected = msg.payload.aircon_overnight === "on";
let maxExportPower = parseFloat(msg.payload.max_export_rate) || 2.0;

let currentBatteryEnergy = (batterySOC / 100) * batteryCapacity;

// Guard: skip if key inputs are missing
if (msg.payload.battery_soc === undefined ||
    msg.payload.battery_capacity === undefined ||
    msg.payload.household_power === undefined) {
    node.warn("Waiting for all sensor data...");
    return null;
}

// ── RESERVE CALCULATION ──────────────────────────────────────────────────────
let overnightReserve = BASE_OVERNIGHT_RESERVE_KWH;
if (airconOvernightExpected) { overnightReserve += AIRCON_ADDITIONAL_RESERVE_KWH; }
let totalReserve = overnightReserve + SAFETY_BUFFER_KWH;

let minSOCEnergy = (MIN_SOC_PERCENT / 100) * batteryCapacity;
let absoluteMinimum = Math.max(totalReserve, minSOCEnergy);

// ── CONSUMPTION AND SOLAR ESTIMATES ──────────────────────────────────────────
let now = new Date();
let currentHour = now.getHours() + (now.getMinutes() / 60);

let avgHouseholdConsumption = currentHouseholdPower;
if (currentHour < 17) { avgHouseholdConsumption = Math.max(currentHouseholdPower, 1.5); }
let householdConsumptionDuringExport = avgHouseholdConsumption * EXPORT_PERIOD_DURATION;

let solarContributionDuringExport = 0;
if (currentHour < EXPORT_PERIOD_START_HOUR) {
    solarContributionDuringExport = Math.min(solarRemaining * 0.10, 2.0);
} else if (currentHour >= EXPORT_PERIOD_START_HOUR && currentHour < EXPORT_PERIOD_END_HOUR) {
    solarContributionDuringExport = Math.min(solarRemaining, 1.5);
}

// ── ENERGY AVAILABLE FOR EXPORT ──────────────────────────────────────────────
let energyAvailableForExport = currentBatteryEnergy - absoluteMinimum;
let netExportableEnergy = energyAvailableForExport + solarContributionDuringExport - householdConsumptionDuringExport;

// ── EXPORT DECISION ──────────────────────────────────────────────────────────
let exportEnabled = false;
let suggestedDischargeRate = 0;
let exportMode = "NONE";
let reason = "";
let confidence = "medium";
let exportEnergyTarget = 0;

if (currentHour >= EXPORT_PERIOD_START_HOUR && currentHour < EXPORT_PERIOD_END_HOUR) {
    let hoursRemainingInExportPeriod = EXPORT_PERIOD_END_HOUR - currentHour;
    let zeroHeroMinEnergy = (ZERO_HERO_MIN_BATTERY_SOC / 100) * batteryCapacity;

    if (batterySOC > ZERO_HERO_MIN_BATTERY_SOC) {
        exportEnabled = true;
        if (netExportableEnergy > 0.5) {
            exportEnergyTarget = Math.min(netExportableEnergy, MAX_EXPORT_CAP_KWH);
            let requiredBatteryDischarge = (exportEnergyTarget + (avgHouseholdConsumption * hoursRemainingInExportPeriod) - solarContributionDuringExport) / hoursRemainingInExportPeriod;
            suggestedDischargeRate = Math.min(Math.max(requiredBatteryDischarge, 0.5), maxExportPower);
            if (suggestedDischargeRate < 0) { suggestedDischargeRate = 0.5; }
            exportMode = "ACTIVE_EXPORT";
            reason = `Exporting ${exportEnergyTarget.toFixed(1)}kWh at ${suggestedDischargeRate.toFixed(1)}kW. Reserve: ${absoluteMinimum.toFixed(1)}kWh${airconOvernightExpected ? ' (aircon expected)' : ''}`;
            confidence = "high";
        } else {
            exportEnabled = true;
            exportEnergyTarget = 0.5;
            suggestedDischargeRate = 0.5;
            exportMode = "ZERO_HERO_PROTECTION";
            reason = `Maintaining feed-in bonus minimum. Net capacity: ${netExportableEnergy.toFixed(1)}kWh. Battery: ${currentBatteryEnergy.toFixed(1)}kWh (${batterySOC.toFixed(0)}% SOC)${airconOvernightExpected ? ', aircon expected' : ''}`;
            confidence = "high";
        }
    } else {
        exportEnabled = false;
        exportMode = "BATTERY_TOO_LOW";
        reason = `Battery too low (${batterySOC.toFixed(0)}% SOC) - protecting overnight reserve.`;
        confidence = "high";
    }

} else if (currentHour < EXPORT_PERIOD_START_HOUR) {
    if (netExportableEnergy > 0.5) {
        exportEnabled = true;
        exportMode = "PLANNED_EXPORT";
        exportEnergyTarget = Math.min(netExportableEnergy, MAX_EXPORT_CAP_KWH);
        suggestedDischargeRate = Math.min(exportEnergyTarget / EXPORT_PERIOD_DURATION, maxExportPower);
        reason = `Planning to export ${exportEnergyTarget.toFixed(1)}kWh during peak period. Current capacity: ${currentBatteryEnergy.toFixed(1)}kWh, reserve: ${absoluteMinimum.toFixed(1)}kWh${airconOvernightExpected ? ' (aircon expected)' : ''}`;
        confidence = currentHour > 16 ? "high" : "medium";
    } else {
        exportEnabled = false;
        exportMode = "PLANNED_NO_EXPORT";
        reason = `Not enough capacity for export. Have ${currentBatteryEnergy.toFixed(1)}kWh, need ${absoluteMinimum.toFixed(1)}kWh reserve${airconOvernightExpected ? ' (aircon expected)' : ''}`;
        confidence = "medium";
    }

} else {
    exportMode = "EXPORT_PERIOD_ENDED";
    reason = "Export period ended. Battery in normal mode.";
    confidence = "high";
    exportEnabled = false;
}

// Time context
let timeContext = "";
if (currentHour < EXPORT_PERIOD_START_HOUR - 2) {
    timeContext = "Early planning - strategy may change";
} else if (currentHour >= EXPORT_PERIOD_START_HOUR - 2 && currentHour < EXPORT_PERIOD_START_HOUR) {
    timeContext = "Approaching export period - final assessment";
    confidence = "high";
} else if (currentHour >= EXPORT_PERIOD_START_HOUR && currentHour < EXPORT_PERIOD_END_HOUR) {
    timeContext = "In export period - feed-in bonus protection active";
    confidence = "high";
} else {
    timeContext = "Export period ended";
}

// Output payload
msg.payload = {
    battery_soc_percent: batterySOC.toFixed(1),
    battery_capacity_kwh: batteryCapacity,
    current_battery_energy_kwh: currentBatteryEnergy.toFixed(2),
    solar_remaining_kwh: solarRemaining,
    current_household_power_kw: currentHouseholdPower,
    aircon_overnight_expected: airconOvernightExpected,
    overnight_reserve_kwh: overnightReserve,
    total_reserve_kwh: totalReserve,
    absolute_minimum_kwh: absoluteMinimum,
    energy_available_for_export_kwh: energyAvailableForExport,
    net_exportable_energy_kwh: netExportableEnergy,
    export_enabled: exportEnabled,
    export_mode: exportMode,
    reason: reason,
    confidence: confidence,
    time_context: timeContext,
    export_energy_target_kwh: parseFloat(exportEnergyTarget.toFixed(2)),
    discharge_rate_kw: parseFloat(suggestedDischargeRate.toFixed(2)),
    max_export_cap_kwh: MAX_EXPORT_CAP_KWH,
    max_export_power_kw: maxExportPower,
    analysis: {
        current_hour: currentHour.toFixed(2),
        hours_until_export_period: Math.max(0, EXPORT_PERIOD_START_HOUR - currentHour).toFixed(1),
        hours_remaining_in_export: Math.max(0, EXPORT_PERIOD_END_HOUR - Math.max(currentHour, EXPORT_PERIOD_START_HOUR)).toFixed(1),
        battery_headroom_above_reserve: Math.max(0, currentBatteryEnergy - absoluteMinimum).toFixed(2) + " kWh",
        zero_hero_minimum_soc: ZERO_HERO_MIN_BATTERY_SOC + "%",
        reserve_breakdown: {
            base_overnight: BASE_OVERNIGHT_RESERVE_KWH + " kWh",
            aircon_additional: airconOvernightExpected ? AIRCON_ADDITIONAL_RESERVE_KWH + " kWh" : "0 kWh",
            safety_buffer: SAFETY_BUFFER_KWH + " kWh",
            total: totalReserve.toFixed(1) + " kWh"
        }
    },
    timestamp: new Date().toISOString()
};

return msg;
